svg.script:
(function() {
  const polygon = document.getElementById("spinner");
  let currentPoints = [];
  let animationsPaused = false;

  // Generar puntos dinámicos (como V2)
  function generateStarPoints(spike = 60) {
    const base = 150;
    const newPoints = [];
    for (let i = 0; i < 8; i++) {
      const angle = (Math.PI * 2 * i) / 8;
      const variation = base + (Math.random() - 0.5) * spike;
      const x = Math.cos(angle) * variation;
      const y = Math.sin(angle) * variation;
      newPoints.push({ x, y });
    }
    return newPoints;
  }

  function interpolatePoints(p1, p2, t) {
    return p1.map((pt, i) => ({
      x: pt.x + (p2[i].x - pt.x) * t,
      y: pt.y + (p2[i].y - pt.y) * t
    }));
  }

  function pointsToString(pts) {
    return pts.map(p => `${p.x.toFixed(2)},${p.y.toFixed(2)}`).join(" ");
  }

  let targetPoints = generateStarPoints();
  currentPoints = targetPoints.map(p => ({ ...p }));
  let tick = 0;

  function animate() {
    if (!animationsPaused && polygon) {
      tick++;
      if (tick % 180 === 0) {
        targetPoints = generateStarPoints(60);
      }

      currentPoints = interpolatePoints(currentPoints, targetPoints, 0.03);
      polygon.setAttribute("points", pointsToString(currentPoints));
    }
    requestAnimationFrame(animate);
  }

  console.log('🏛️ Parlamento de Todas las Cosas Fase 2 cargado');
  console.log('🧬 Agentes eDNA: 8 sitios de muestreo regionales');
  console.log('🍄 Redes fúngicas: 4 nodos micorrízicos');  
  console.log('🤖 Agencia Evolución IA: Meta-gobernanza activa');
  console.log('🌍 Total agentes: 21 participantes democráticos multi-modales');
  console.log('📚 Marco teórico: Teoría Actor-Red Bruno Latour');
  console.log('🎨 Inspiración artística: Soleiman López - Festival de la Imagen 2025');

  // Interacción mínima para Fase 2
  const allAgents = document.querySelectorAll('.species-seat, .ai-core, [class*="edna"], [class*="fungi"]');
  allAgents.forEach(agent => {
    agent.addEventListener('click', function() {
      console.log('Agente activado - Democracia multi-modal Fase 2');
    });
  });

  // Tecla ESPACIO pausa/reanuda animaciones
  document.addEventListener('keydown', function(e) {
    if (e.code === 'Space') {
      e.preventDefault();
      animationsPaused = !animationsPaused;

      const allAnimated = document.querySelectorAll('.parliament-seats, .edna-particle, .fungi-network, .ai-core, .agent-connection');
      allAnimated.forEach(el => {
        el.style.animationPlayState = animationsPaused ? 'paused' : 'running';
      });

      console.log(animationsPaused ? '⏸️ Parlamento Fase 2 pausado' : '▶️ Parlamento Fase 2 reanudado');
    }
  });

  // Iniciar animación del polígono
  animate();
})();
